        { referencia: "Apocalipse 13:11-15", descricao: "referido em Apocalipse 16:13; 19:20 - besta da terra (falso profeta); 1 Reis 18:38; 2 Reis 1:10-12 - fogo do céu." },
        { referencia: "Apocalipse 13:16-18", descricao: "referido em Apocalipse 14:9-11; 15:2; 16:2; 19:20; 20:4 - marca da besta; 1 Reis 10:14; Esdras 2:13 - número 666." }
