        { referencia: "Apocalipse 18:20", descricao: "referido em Deuteronômio 32:43; Jeremias 51:48; Apocalipse 12:12 - alegria no céu." },
        { referencia: "Apocalipse 18:21-24", descricao: "referido em Jeremias 51:63-64; Ezequiel 26:21; Jeremias 7:34; 25:10; Isaías 24:8 - destruição total." }
